customCss:
.single-summary-card-container {
            font-family: 'Noto Sans KR', sans-serif;
            display: flex;
            justify-content: center;
            align-items: center;
            padding: 20px 10px;
            background-color: #f0f4f8;
            margin: 20px 0;
        }
        .single-summary-card {
            width: 100%;
            max-width: 700px;
            background-color: #ffffff;
            border-radius: 12px;
            box-shadow: 0 6px 18px rgba(0,0,0,0.1);
            padding: 25px;
            display: flex;
            flex-direction: column;
            overflow: hidden;
            border: 1px solid #cfd8dc;
            box-sizing: border-box;
            height: auto;
        }
        .single-summary-card .card-header {
            display: flex;
            align-items: center;
            border-bottom: 2px solid #1a73e8;
            padding-bottom: 12px;
            margin-bottom: 12px;
        }
        .single-summary-card .card-header-icon {
            font-size: 34px;
            color: #1a73e8;
            margin-right: 14px;
        }
        .single-summary-card .card-header h3 {
            font-size: 26px;
            color: #1a73e8;
            margin: 0;
            line-height: 1.3;
            font-weight: 700;
        }
        .single-summary-card .card-content {
            flex-grow: 1;
            display: flex;
            flex-direction: column;
            justify-content: space-around;
            font-size: 17px;
            line-height: 1.65;
            color: #333;
        }
        .single-summary-card .card-content .section {
            margin-bottom: 10px;
        }
        .single-summary-card .card-content strong {
            color: #1a73e8;
            font-weight: 600;
        }
        .single-summary-card .card-content .highlight {
            background-color: #e8f4fd;
            padding: 2px 6px;
            border-radius: 3px;
            font-weight: bold;
        }
        .single-summary-card .card-content .formula {
            background-color: #f8f9fa;
            padding: 6px 10px;
            border-radius: 4px;
            font-size: 0.9em;
            text-align: center;
            margin-top: 5px;
            color: #333;
            border: 1px solid #cfd8dc;
        }
        .single-summary-card .card-footer {
            font-size: 14px;
            color: #777;
            text-align: center;
            padding-top: 12px;
            border-top: 1px dashed #cfd8dc;
            margin-top: auto;
        }

        @media (max-width: 768px) {
            .single-summary-card {
                padding: 18px;
            }
            .single-summary-card .card-header-icon {
                font-size: 28px;
                margin-right: 10px;
            }
            .single-summary-card .card-header h3 {
                font-size: 20px;
            }
            .single-summary-card .card-content {
                font-size: 15px;
                line-height: 1.5;
            }
            .single-summary-card .card-content .section {
                margin-bottom: 8px;
            }
            .single-summary-card .card-content .formula {
                padding: 5px 8px;
                font-size: 0.85em;
            }
            .single-summary-card .card-footer {
                font-size: 13px;
                padding-top: 10px;
            }
        }
